#include "ring_buffer.h"
#define MAX_BUF 512
static float _buf[MAX_BUF];
static uint16_t _cap=256,_head=0,_tail=0,_count=0;
void rbuf_setup(uint16_t c){_cap=min(c,(uint16_t)MAX_BUF);_head=0;_tail=0;_count=0;}
void rbuf_push(float v){_buf[_head]=v;_head=(_head+1)%_cap;if(_count<_cap)_count++;else _tail=(_tail+1)%_cap;}
float rbuf_pop(){if(!_count)return 0;float v=_buf[_tail];_tail=(_tail+1)%_cap;_count--;return v;}
float rbuf_peek(){return _count?_buf[_tail]:0;}
uint16_t rbuf_count(){return _count;}
bool rbuf_full(){return _count>=_cap;}
bool rbuf_empty(){return _count==0;}
float rbuf_average(){if(!_count)return 0;float s=0;for(uint16_t i=0;i<_count;i++)s+=_buf[(_tail+i)%_cap];return s/_count;}
